  1168→// Submit a response in a mock interview — AI responds conversationally
  1169→router.post('/mock/:sessionId/respond', authMiddleware, async (req, res) => {
  1170→  try {
  1171→    const { response_text } = req.body;
  1172→    const sessionId = req.params.sessionId;
  1173→
  1174→    if (!response_text || response_text.trim().length < 10) {
  1175→      return res.status(400).json({ error: 'Response too short. Please elaborate on your answer.' });
  1176→    }
  1177→
  1178→    // Get session
  1179→    const sessionResult = await pool.query(
  1180→      'SELECT * FROM mock_interview_sessions WHERE id = $1 AND user_id = $2 AND status = $3',
  1181→      [sessionId, req.user.id, 'in_progress']
  1182→    );
  1183→
  1184→    if (sessionResult.rows.length === 0) {
  1185→      return res.status(404).json({ error: 'Session not found or already completed' });
  1186→    }
  1187→
  1188→    const session = sessionResult.rows[0];
  1189→    const conversation = session.conversation || [];
  1190→    const questionIds = session.question_ids || [];
  1191→
  1192→    // Get base questions from bank
  1193→    const questionsResult = await pool.query(
  1194→      'SELECT * FROM question_bank WHERE id = ANY($1)',
  1195→      [questionIds]
  1196→    );
  1197→    // Maintain order from questionIds
  1198→    const questionMap = {};
  1199→    questionsResult.rows.forEach(q => { questionMap[q.id] = q; });
  1200→    const baseQuestions = questionIds.map(id => questionMap[id]).filter(Boolean);
  1201→
  1202→    // Add candidate response to conversation
  1203→    const candidateMessage = {
  1204→      role: 'candidate',
  1205→      text: response_text.trim(),
  1206→      timestamp: new Date().toISOString()
  1207→    };
  1208→    conversation.push(candidateMessage);
  1209→
  1210→    // AI generates next interviewer turn (with fallback on failure)
  1211→    let aiTurn;
  1212→    try {
  1213→      aiTurn = await conductInterviewTurn(
  1214→        conversation,
  1215→        baseQuestions,
  1216→        session.current_question_index,
  1217→        session.target_role,
  1218→        { subscriptionId: req.user.stripe_subscription_id }
  1219→      );
  1220→    } catch (aiErr) {
  1221→      console.warn(`[mock] AI turn generation failed (${aiErr.message}), using scripted fallback`);
  1222→      // Scripted fallback: acknowledge answer and move to next question from bank
  1223→      const nextIdx = session.current_question_index + 1;
  1224→      const nextQ = baseQuestions[nextIdx];
  1225→      const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1226→      if (nextQ && candidateTurnCount < 8) {
  1227→        aiTurn = {
  1228→          reaction: "Thank you for that response. That's helpful context.",
  1229→          action: 'transition',
  1230→          question: nextQ.question_text,
  1231→          score_hint: null,
  1232→          notes: 'AI unavailable — scripted transition'
  1233→        };
  1234→      } else {
  1235→        aiTurn = {
  1236→          reaction: "Thank you for sharing all of that. I think we've covered a good range of topics.",
  1237→          action: 'wrap_up',
  1238→          question: "Is there anything else you'd like to add before we wrap up?",
  1239→          score_hint: null,
  1240→          notes: 'AI unavailable — scripted wrap-up'
  1241→        };
  1242→      }
  1243→    }
  1244→
  1245→    // Build interviewer message
  1246→    let interviewerText = aiTurn.reaction || '';
  1247→    if (aiTurn.question) {
  1248→      interviewerText += (interviewerText ? '\n\n' : '') + aiTurn.question;
  1249→    }
  1250→
  1251→    const interviewerMessage = {
  1252→      role: 'interviewer',
  1253→      text: interviewerText,
  1254→      action: aiTurn.action || 'transition',
  1255→      score_hint: aiTurn.score_hint || null,
  1256→      notes: aiTurn.notes || null,
  1257→      timestamp: new Date().toISOString()
  1258→    };
  1259→    conversation.push(interviewerMessage);
  1260→
  1261→    // Update session
  1262→    const isWrappingUp = aiTurn.action === 'wrap_up';
  1263→    const isTransition = aiTurn.action === 'transition';
  1264→    const newQuestionIndex = isTransition
  1265→      ? Math.min(session.current_question_index + 1, baseQuestions.length)
  1266→      : session.current_question_index;
  1267→    const newFollowUps = (aiTurn.action === 'follow_up' || aiTurn.action === 'challenge')
  1268→      ? (session.follow_ups_asked || 0) + 1
  1269→      : session.follow_ups_asked || 0;
  1270→
  1271→    // Increment times_used for the new question if transitioning
  1272→    if (isTransition && newQuestionIndex < baseQuestions.length) {
  1273→      const nextQ = baseQuestions[newQuestionIndex];
  1274→      if (nextQ) {
  1275→        await pool.query('UPDATE question_bank SET times_used = times_used + 1 WHERE id = $1', [nextQ.id]);
  1276→      }
  1277→    }
  1278→
  1279→    await pool.query(
  1280→      `UPDATE mock_interview_sessions
  1281→       SET conversation = $1, current_question_index = $2,
  1282→           questions_asked = $3, follow_ups_asked = $4
  1283→       WHERE id = $5`,
  1284→      [
  1285→        JSON.stringify(conversation),
  1286→        newQuestionIndex,
  1287→        isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1288→        newFollowUps,
  1289→        sessionId
  1290→      ]
  1291→    );
  1292→
  1293→    // BUG FIX: Pre-generate feedback in background after 3+ candidate turns
  1294→    // This dramatically reduces wait time when user clicks "End"
  1295→    const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
