  1306→        })
  1307→        .catch(err => console.warn('[mock] Background feedback generation failed:', err.message));
  1308→    }
  1309→
  1310→    res.json({
  1311→      success: true,
  1312→      interviewer_message: interviewerMessage,
  1313→      action: aiTurn.action,
  1314→      questions_asked: isTransition ? (session.questions_asked || 0) + 1 : session.questions_asked || 0,
  1315→      is_wrapping_up: isWrappingUp
  1316→    });
  1317→  } catch (err) {
  1318→    console.error('Mock interview respond error:', err);
