  1577→// Real-time single-frame body language analysis (lightweight, called every ~20s during interview)
  1578→router.post('/mock/analyze-frame', authMiddleware, async (req, res) => {
  1579→  try {
  1580→    const { frame } = req.body;
  1581→    if (!frame) {
  1582→      return res.status(400).json({ error: 'No frame provided' });
  1583→    }
  1584→
  1585→    // Upload single frame to R2
  1586→    const { uploadFrameToR2 } = require('../lib/polsia-ai');
  1587→    const frameUrl = await uploadFrameToR2(frame, 0);
  1588→    if (!frameUrl) {
  1589→      return res.json({ success: false, error: 'Frame upload failed' });
  1590→    }
  1591→
  1592→    // Quick analysis with vision API — uses provider fallback (GPT-4o → NIM Cosmos → NIM Nemotron VL)
  1593→    const { aiProvider } = require('../lib/polsia-ai');
  1594→    const analysisPrompt = `Quick interview body language check. Rate each as "good", "fair", or "poor" with a 2-3 word tip. Return JSON only:
  1595→{"eye_contact":"good|fair|poor","posture":"good|fair|poor","confidence":"good|fair|poor","expression":"good|fair|poor","tip":"brief tip"}`;
  1596→
  1597→    const text = await aiProvider.visionAnalysis([frameUrl], analysisPrompt, {
  1598→      maxTokens: 200,
  1599→      task: 'interview-realtime-body-language',
  1600→    });
  1601→    let indicators;
  1602→    try {
  1603→      const jsonMatch = text.match(/\{[\s\S]*\}/);
  1604→      indicators = jsonMatch ? JSON.parse(jsonMatch[0]) : null;
  1605→    } catch {
  1606→      indicators = null;
  1607→    }
